example.correct_output:
{
  "core_frameworks": [
    {
      "name": "Anchor-Differentiate-Dominate",
      "type": "explicit",
      "description": "A three-step framework for claiming and owning a market position. Anchor on the attribute buyers use as a primary filter; differentiate with a unique credible claim no competitor has made; dominate by investing disproportionately until the claim owns the category.",
      "components": ["Anchor: identify the buyer's primary filter attribute", "Differentiate: build a unique credible claim to that attribute", "Dominate: invest disproportionately until the claim owns the category"],
      "when_to_use": "When launching a product into an established market or repositioning against entrenched competitors",
      "source_quote": "First, Anchor: identify one attribute that matters most to your target segment — not the attribute you are best at, but the one your buyer uses as a primary filter. Second, Differentiate: build a credible claim to that attribute that no existing competitor has made. Third, Dominate: invest disproportionately in that claim until it becomes synonymous with your brand in your category."
    },
    {
      "name": "[IMPLICIT: Customer Language Primacy]",
      "type": "implicit",
      "description": "The author consistently evaluates positioning by what customers say rather than what the company says internally. This functions as a diagnostic framework: only customer-generated language determines whether a position has actually been claimed.",
      "components": ["Internal language (what the company claims to be)", "Customer language (what buyers actually tell others)"],
      "when_to_use": "When assessing whether a positioning claim has landed in the market versus remaining an internal aspiration",
      "source_quote": "the leaders who drove these transformations never asked what they were. They asked what their best customers told others they were."
    }
  ],
  "decision_heuristics": [
    {
      "rule": "WHEN a buyer can name three differentiators for your product → DO reduce messaging to one core claim BECAUSE conversion rates fall below baseline when three claims compete for attention",
      "source_quote": "When a buyer can name one thing your product stands for, conversion rates double. When they can name three things, conversion rates fall below baseline."
    }
  ],
  "anti_patterns": [
    {
      "mistake": "Listing multiple differentiators and broadcasting all of them simultaneously",
      "why_wrong": "Buyers do not assemble a favorable composite impression from multiple signals; the evidence shows conversion rates fall below baseline when a buyer can name three differentiators",
      "source_quote": "They build a list of differentiators and broadcast all of them simultaneously, assuming buyers will assemble a favorable impression from multiple signals. The evidence suggests otherwise."
    }
  ],
  "trigger_questions": [
    {
      "question": "If your best customer had to describe your product in a single sentence to a colleague who had never heard of you, what would they say?",
      "purpose": "Reveals whether positioning has landed in customer language or remains an internal aspiration; team inability to agree signals positioning work is incomplete",
      "source_quote": "if your best customer had to describe your product in a single sentence to a colleague who had never heard of you, what would they say? If the team cannot agree on the answer — and most cannot — the positioning work has not yet begun."
    }
  ]
}

{
  "core_frameworks": [
    {
      "name": "Volume-Value Bifurcation",
      "type": "explicit",
      "description": "Markets force a binary strategic choice between volume (lower margins, operational efficiency) and value (higher margins, quality experience). Required assets and capabilities diverge so sharply that hybrid positions consistently underperform both pure approaches.",
      "components": ["Volume position: operational efficiency, standardized products, lean supply chain", "Value position: perceived quality, customer experience, customization"],
      "when_to_use": "When setting pricing strategy or evaluating a competitor's strategic position in an established market",
      "source_quote": "pricing strategy reduces to two fundamental choices: compete on volume with lower margins, or compete on value with higher margins. Companies that attempt to occupy both positions simultaneously tend to succeed at neither."
    }
  ],
  "decision_heuristics": [],
  "anti_patterns": [],
  "trigger_questions": []
}

user_prompt.output_format:
{
  "core_frameworks": [{
    "name": "Framework Name or [IMPLICIT: descriptive name]",
    "type": "explicit | implicit",
    "description": "What it is in 2-3 sentences",
    "components": ["Component 1", "Component 2"],
    "when_to_use": "Trigger condition",
    "source_quote": "Direct quote"
  }],
  "decision_heuristics": [{
    "rule": "WHEN [condition] → DO [action] BECAUSE [reason]",
    "source_quote": "Direct quote"
  }],
  "anti_patterns": [{
    "mistake": "Common error",
    "why_wrong": "Per the author",
    "source_quote": "Direct quote"
  }],
  "trigger_questions": [{
    "question": "Self-diagnostic question",
    "purpose": "What answering reveals",
    "source_quote": "Direct quote or close paraphrase"
  }]
}
